// frontend/src/components/Navbar/Navbar.js
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const Navbar = ({ isAuthenticated, handleLogout }) => {
    const navigate = useNavigate();
    const [hoveredMenu, setHoveredMenu] = useState(null);

    return (
        <nav style={{ 
            display: 'flex', justifyContent: 'space-between', alignItems: 'center', 
            padding: '20px 5%', background: '#0c0a09', borderBottom: '1px solid #262626' 
        }}>
            <div onClick={() => navigate('/')} style={{ cursor: 'pointer', color: '#fef3c7' }}>
                <h2>PasukanYerusSolo</h2>
            </div>

            <div className="nav-menu">
                {isAuthenticated ? (
                    <>
                        <button 
                            onClick={handleLogout} // <--- Fungsi ini sekarang terhubung
                            style={{ 
                                background: 'transparent', border: '1px solid #ef4444', 
                                padding: '6px 16px', borderRadius: '20px',
                                color: hoveredMenu === 'logout' ? '#fff' : '#ef4444', 
                                fontWeight: '700', fontSize: '12px', cursor: 'pointer', transition: '0.3s' 
                            }}
                            onMouseEnter={() => setHoveredMenu('logout')}
                            onMouseLeave={() => setHoveredMenu(null)}
                        >Keluar</button>
                    </>
                ) : (
                    <button 
                        onClick={() => navigate('/login')} 
                        style={{ 
                            padding: '6px 16px', borderRadius: '20px', 
                            border: '1px solid #ea580c', 
                            background: hoveredMenu === 'login' ? '#ea580c' : 'transparent', 
                            color: hoveredMenu === 'login' ? '#fff' : '#ea580c', 
                            fontWeight: '700', fontSize: '12px', cursor: 'pointer', transition: '0.3s' 
                        }}
                        onMouseEnter={() => setHoveredMenu('login')}
                        onMouseLeave={() => setHoveredMenu(null)}
                    >Login</button>
                )}
            </div>
        </nav>
    );
};

export default Navbar;
